import time
from dataclasses import dataclass, field
from typing import Optional, List, Dict


@dataclass
class Task:
    id: int
    name: str
    priority: int
    due: float
    completed: bool = False
    created: float = field(default_factory=time.time)


class TaskScheduler:
    def __init__(self):
        self._tasks: Dict[int, Task] = {}
        self._next_id: int = 1

    def add_task(self, name: str, priority: int, due_timestamp: float) -> int:
        task = Task(
            id=self._next_id,
            name=name,
            priority=priority,
            due=due_timestamp,
        )
        self._tasks[task.id] = task
        self._next_id += 1
        return task.id

    def complete_task(self, task_id: int) -> bool:
        task = self._tasks.get(task_id)
        if task is None:
            return False
        task.completed = True
        return True

    def get_pending(self) -> List[Task]:
        pending = [t for t in self._tasks.values() if not t.completed]
        return sorted(pending, key=lambda t: (-t.priority, t.due))

    def get_overdue(self) -> List[Task]:
        now = time.time()
        return [t for t in self._tasks.values() if not t.completed and t.due < now]

    def delete_task(self, task_id: int) -> bool:
        return self._tasks.pop(task_id, None) is not None

    def get_stats(self) -> dict:
        tasks = list(self._tasks.values())
        completed = sum(1 for t in tasks if t.completed)
        return {
            'total': len(tasks),
            'completed': completed,
            'pending': len(tasks) - completed,
        }
